---@type LMapBase
local LMapBase = LMapBase

function LMapBase:RegisterRedPointFunc(redPointType,func)
    if not gModelRedPoint then return end

    if not self._redListenerList then
        self._redListenerList={}
    end

    local list  = self._redListenerList[redPointType]
    if not list then
        list = {}
        self._redListenerList[redPointType] =list
    end
    table.insert(list,func)

    local isShowRed = gModelRedPoint:CheckShowRedPoint(redPointType)
    func(isShowRed)
    gModelRedPoint:OnRedPointRegister(redPointType)
end

function LMapBase:ReleaseRedPointFunc()
    if self._redListenerList then
        for k,v in pairs(self._redListenerList) do
            gModelRedPoint:OnRedPointRelease(k)
        end
    end

    self._redListenerList=nil
end

function LMapBase:OnTryRefreshRedPoint(...)

end

function LMapBase:RefreshRedPoint(redPointType)
    if not self._redListenerList then return end

    local list  = self._redListenerList[redPointType]
    if not list then return end

    local showRed = gModelRedPoint:CheckShowRedPoint(redPointType)
    for k,v in ipairs(list) do
        v(showRed)
    end
end

function LMapBase:RegisterRedPoint()
    if not gModelRedPoint then return end

    local pathConfig = gModelRedPoint:GetRedPathConfig()
    if not pathConfig then return end

    local mapName = self:GetMapName()
    local list = pathConfig[mapName]
    if not list then return end

    local scene = GF.GetNowSceneClass()
    local mapRoot = nil
    if scene and scene.GetMapRoot then
        mapRoot = scene:GetMapRoot()
    end

    --主场景的红点节点需要特殊处理
    if mapName=="MapCity" then
        --  "UIBubbleStick"
        mapRoot= CS.FindTrans(LGameUI.GetUIFight(), "UIBubbleStick")
    end

    if not mapRoot then return end

    -- baowu/CityEnterBubble/timeBg/redPoint UIBubbleStick
    -- RehtGame/RootUI/UICanvas/UIFight/UIBubbleStick/baowu




    for k,v in pairs(list) do
        local redPointTran = mapRoot:Find(v.path)
        if not CS.IsValidObject(redPointTran) then
            --if LOG_INFO_ENABLED then
            --    local str = "redpoint path is Wrong id %s ,path %s"
            --    printErrorN(string.format(str,v.typeId,v.path))
            --end
        else
            local pointType = v.pointType-1
            self:SetImageActorState(redPointTran,pointType)

            self:RegisterRedPointFunc(v.typeId,function (isShow)
                if self._isHideRedPoint then
                    isShow = false
                end
                CS.ShowObject(redPointTran,isShow)
            end)
        end

    end

end

function LMapBase:HideAllRedPoint()
    self._isHideRedPoint = true
    if not self._redListenerList then return end

    for k,v in pairs(self._redListenerList) do
        for k1,v1 in ipairs(v) do
            v1(false)
        end
    end
end

function LMapBase:RefreshAllRedPoint()
    self._isHideRedPoint = false
    if not self._redListenerList then return end

    for k,v in pairs(self._redListenerList) do
        local isShowRed = gModelRedPoint:CheckShowRedPoint(k)
        for k1,v1 in ipairs(v) do
            v1(isShowRed)
        end
    end
end
